import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';
import { DateResolver } from '../core/processors/DateResolver';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    /**
     * Adiciona transações em lote com CHUNKING para evitar estouro de buffer e timeout.
     */
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const sanitizedPayload = transactions
                .map(t => {
                    const amount = Number(t.amount);
                    let finalDate = t.transaction_date;

                    // Normalização de segurança para ISO YYYY-MM-DD
                    if (finalDate && !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        const resolved = DateResolver.resolveToISO(finalDate, new Date().getFullYear());
                        if (resolved) finalDate = resolved;
                    }

                    if (!finalDate || !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        finalDate = new Date().toISOString().split('T')[0];
                    }

                    return {
                        transaction_date: finalDate,
                        amount: isNaN(amount) ? 0 : amount,
                        description: t.description,
                        type: t.type || (amount >= 0 ? 'income' : 'expense'),
                        pix_key: t.pix_key || null,
                        source: t.source || 'file',
                        user_id: t.user_id,
                        bank_id: t.bank_id || null, 
                        status: t.status || 'pending',
                        row_hash: t.row_hash
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null && !!item.user_id);

            if (sanitizedPayload.length === 0) return [];

            const CHUNK_SIZE = 200;
            const results = [];

            for (let i = 0; i < sanitizedPayload.length; i += CHUNK_SIZE) {
                const chunk = sanitizedPayload.slice(i, i + CHUNK_SIZE);

                const { data, error } = await supabase
                    .from('consolidated_transactions')
                    .insert(chunk)
                    .select('*'); 

                if (error) {
                    console.error("[Consolidation:INSERT_ERROR]", error);
                    throw new Error(error.message);
                }
                if (data) results.push(...data);
            }

            return results;
        } catch (e: any) {
            console.error("[Consolidation:CRITICAL_FAIL]", e);
            throw e;
        }
    },

    /**
     * Atualiza o status de uma transação no banco de dados.
     * Essencial para remover itens da Lista Viva após identificação.
     */
    updateTransactionStatus: async (id: string, status: 'pending' | 'identified' | 'resolved') => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .update({ status })
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao atualizar status:", error);
            return false;
        }
    },

    /**
     * Recupera hashes existentes com limite estendido para 50k registros.
     */
    getExistingTransactionsForDedup: async (userId: string) => {
        try {
            if (!userId) throw new Error("UserID é obrigatório.");

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('row_hash')
                .eq('user_id', userId)
                .limit(50000); // Limite aumentado drasticamente

            if (error) throw error;
            return data || [];
        } catch (e: any) {
            throw e;
        }
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!userId) return false;

            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId && bankId !== 'all') {
                const isVirtual = bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank';
                const isProbablyUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
                if (isVirtual || !isProbablyUuid) query = query.is('bank_id', null);
                else query = query.eq('bank_id', bankId);
            }
            const { error } = await query;
            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    },

    /**
     * Recupera transações pendentes com limite estendido para 50k registros.
     */
    getPendingTransactions: async (userId: string) => {
        try {
            if (!userId) return [];

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('id, transaction_date, amount, description, type, bank_id, row_hash, pix_key')
                .eq('user_id', userId)
                .eq('status', 'pending')
                .order('transaction_date', { ascending: false })
                .limit(50000); // Limite aumentado drasticamente

            if (error) throw error;
            return data || [];
        } catch (e: any) {
            throw e; 
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';
import { useUI } from '../contexts/UIContext';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds
}: any) => {
    const { showToast } = useUI();
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    // ✅ Normalizadores para dedupe lógico
    const normalizeDate = (d: any) => {
        if (!d) return '';
        const dt = new Date(d);
        if (isNaN(dt.getTime())) return String(d);
        return dt.toISOString().slice(0, 10);
    };

    const normalizeText = (t: any) =>
        String(t || '')
            .toLowerCase()
            .trim()
            .replace(/\s+/g, ' ');

    const normalizeAmount = (v: any) =>
        Number(v || 0).toFixed(2);

    const buildKey = (tx: any, bankId: string) =>
        `${normalizeDate(tx.date)}|${normalizeText(tx.description)}|${normalizeAmount(tx.amount)}|${bankId}`;

    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                if (forceClearUI) {
                    setBankStatementFile(() => []);
                    setSelectedBankIds(() => []);
                }
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                let bankId = t.bank_id;
                if (!bankId && t.pix_key && t.pix_key.includes('-')) {
                    bankId = t.pix_key;
                }
                const finalBankId = bankId || 'virtual';

                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: t.pix_key || 'OUTROS',
                    cleanedDescription: t.description,
                    bank_id: t.bank_id
                };

                if (!groupedByBank[finalBankId]) groupedByBank[finalBankId] = [];
                groupedByBank[finalBankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId.includes('gmail')
                    ? 'Importação Gmail'
                    : (bankId === 'virtual' ? 'Lista Virtual' : `Lista Viva Sincronizada`),
                processedTransactions: txs,
                isRestored: true
            }));

            // ✅ MERGE + DEDUPE ROBUSTO (ID > TEXTO)
            setBankStatementFile((prev: any[]) => {
                if (!prev || prev.length === 0) return restoredFiles;

                const map = new Map<string, any>();
                prev.forEach(f => map.set(f.bankId, f));

                restoredFiles.forEach(f => {
                    if (map.has(f.bankId)) {
                        const existing = map.get(f.bankId);
                        const txMap = new Map<string, any>();

                        // Mapeia existentes
                        existing.processedTransactions.forEach((tx: any) => {
                            // Prioridade total ao ID único do banco para evitar duplicados "ressuscitados"
                            const key = tx.id && !tx.id.includes('ghost') && !tx.id.includes('sim') 
                                ? tx.id 
                                : buildKey(tx, f.bankId);
                            txMap.set(key, tx);
                        });

                        // Funde novos (do banco) apenas se não existirem
                        f.processedTransactions.forEach((tx: any) => {
                            const key = tx.id ? tx.id : buildKey(tx, f.bankId);
                            if (!txMap.has(key)) {
                                txMap.set(key, tx);
                            }
                        });

                        map.set(f.bankId, {
                            ...existing,
                            processedTransactions: Array.from(txMap.values())
                        });
                    } else {
                        map.set(f.bankId, f);
                    }
                });

                return Array.from(map.values());
            });

            setSelectedBankIds((prev: string[]) => {
                const availableIds = restoredFiles.map(f => f.bankId);
                return Array.from(new Set([...prev.filter(id => availableIds.includes(id)), ...availableIds]));
            });

        } catch (err: any) {
            console.error("[Lista Viva] Erro na hidratação:", err);
            showToast("Falha ao sincronizar Lista Viva.", "error");
        } finally {
            isHydrating.current = false;
        }
    }, [user, setBankStatementFile, setSelectedBankIds, isCleaning, showToast]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
            return stats;
        } catch (e: any) {
            showToast("Erro no Lançamento: " + (e.message || "Erro de rede."), "error");
            throw e; 
        }
    }, [user, showToast]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile([]);
                setSelectedBankIds([]);
            }
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

import { useCallback } from 'react';
import { MatchResult, Church, ReconciliationStatus, MatchMethod, Contributor } from '../types';
import { groupResultsByChurch } from '../services/processingService';
import { consolidationService } from '../services/ConsolidationService';

interface UseReconciliationActionsProps {
  reconciliation: any;
  referenceData: any;
  showToast: (msg: string, type: 'success' | 'error') => void;
  onAfterAction?: (updatedResults: MatchResult[]) => void;
}

export const useReconciliationActions = ({
  reconciliation,
  referenceData,
  showToast,
  onAfterAction
}: UseReconciliationActionsProps) => {

  const confirmManualIdentification = useCallback(async (txId: string, churchId: string) => {
    const church = referenceData.churches.find((c: Church) => c.id === churchId);
    if (!church) return;

    const currentResults = [...reconciliation.matchResults];
    const idx = currentResults.findIndex(r => r.transaction.id === txId);
    if (idx === -1) return;

    const originalResult = currentResults[idx];

    // 🎯 AJUSTE CRÍTICO: Se não houver contribuinte, cria um virtual baseado na descrição
    const contributor: Contributor = originalResult.contributor || {
        name: originalResult.transaction.cleanedDescription || originalResult.transaction.description,
        amount: originalResult.transaction.amount,
        cleanedName: originalResult.transaction.cleanedDescription || originalResult.transaction.description
    };

    const updatedResult: MatchResult = {
      ...originalResult,
      status: ReconciliationStatus.IDENTIFIED,
      contributor: contributor,
      church: church,
      matchMethod: MatchMethod.MANUAL,
      similarity: 100,
      contributorAmount: contributor.amount,
      divergence: undefined
    };

    currentResults[idx] = updatedResult;

    // Persistência de Status no Banco (Consome a pendência)
    if (!txId.includes('ghost') && !txId.includes('sim')) {
        await consolidationService.updateTransactionStatus(txId, 'identified');
    }

    reconciliation.setMatchResults(currentResults);
    referenceData.learnAssociation(updatedResult);

    reconciliation.closeManualIdentify();
    showToast("Identificado e aprendido pela IA.", "success");

    if (onAfterAction) onAfterAction(currentResults);
  }, [reconciliation, referenceData, showToast, onAfterAction]);

  const confirmBulkManualIdentification = useCallback(async (txIds: string[], churchId: string) => {
    const church = referenceData.churches.find((c: Church) => c.id === churchId);
    if (!church) return;

    const currentResults = [...reconciliation.matchResults];
    let affectedCount = 0;

    for (const id of txIds) {
      const idx = currentResults.findIndex(r => r.transaction.id === id);
      if (idx !== -1) {
        const original = currentResults[idx];

        const contributor: Contributor = original.contributor || {
            name: original.transaction.cleanedDescription || original.transaction.description,
            amount: original.transaction.amount,
            cleanedName: original.transaction.cleanedDescription || original.transaction.description
        };

        const updated: MatchResult = {
          ...original,
          status: ReconciliationStatus.IDENTIFIED,
          contributor: contributor,
          church,
          matchMethod: MatchMethod.MANUAL,
          similarity: 100,
          contributorAmount: contributor.amount,
          divergence: undefined
        };
        currentResults[idx] = updated;
        referenceData.learnAssociation(updated);

        // Consome no banco em lote
        if (!id.includes('ghost') && !id.includes('sim')) {
            await consolidationService.updateTransactionStatus(id, 'identified');
        }

        affectedCount++;
      }
    }

    reconciliation.setMatchResults(currentResults);

    if (reconciliation.setReportPreviewData) {
        const incomeResults = currentResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val >= 0;
        });
        const expenseResults = currentResults.filter(r => {
            const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
            return val < 0;
        });

        reconciliation.setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }

    reconciliation.closeManualIdentify();
    showToast(`${affectedCount} registros identificados e aprendidos.`, "success");

    if (onAfterAction) onAfterAction(currentResults);
  }, [reconciliation, referenceData, showToast, onAfterAction]);

  const undoIdentification = useCallback(async (txId: string) => {
    // Reverte status no banco de dados para que volte à Lista Viva
    if (!txId.includes('ghost') && !txId.includes('sim')) {
        await consolidationService.updateTransactionStatus(txId, 'pending');
    }

    reconciliation.revertMatch(txId);
    showToast("Identificação desfeita.", "success");

    setTimeout(() => {
        if (onAfterAction) onAfterAction(reconciliation.matchResults);
    }, 100);
  }, [reconciliation, showToast, onAfterAction]);

  return {
    confirmManualIdentification,
    confirmBulkManualIdentification,
    undoIdentification
  };
};

import { useCallback } from 'react';
import { ReconciliationStatus, MatchMethod, MatchResult } from '../types';
import { strictNormalize, groupResultsByChurch } from '../services/processingService';
import { consolidationService } from '../services/ConsolidationService';

interface UseAiAutoIdentifyProps {
    reconciliation: any;
    referenceData: any;
    effectiveIgnoreKeywords: string[];
    setIsLoading: (loading: boolean) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    onAfterIdentification?: (results: MatchResult[]) => void;
}

/**
 * Calcula similaridade de tokens.
 */
const getConfidenceScore = (s1: string, s2: string): number => {
    if (s1 === s2) return 100;
    const clean1 = s1.replace(/[^A-Z0-9]/g, '');
    const clean2 = s2.replace(/[^A-Z0-9]/g, '');
    if (clean1 === clean2 && clean1.length > 0) return 100;

    const set1 = new Set();
    for (let i = 0; i < s1.length - 1; i++) set1.add(s1.substring(i, i + 2));
    const set2 = new Set();
    for (let i = 0; i < s2.length - 1; i++) set2.add(s2.substring(i, i + 2));

    const intersection = new Set([...set1].filter(x => set2.has(x)));
    const total = set1.size + set2.size;
    if (total === 0) return 0;
    return (2.0 * intersection.size) / total * 100;
};

export const useAiAutoIdentify = ({
    reconciliation,
    referenceData,
    setIsLoading,
    showToast,
    onAfterIdentification
}: UseAiAutoIdentifyProps) => {

    const runAiAutoIdentification = useCallback(async () => {
        const { matchResults, setMatchResults, setReportPreviewData } = reconciliation;
        const { learnedAssociations, churches } = referenceData;

        if (!matchResults || matchResults.length === 0) {
            showToast("Nenhuma transação carregada para identificar.", "error");
            return;
        }

        setIsLoading(true);
        let identifiedCount = 0;

        const nextResults = [];

        for (const res of matchResults) {
            if (res.status === ReconciliationStatus.UNIDENTIFIED) {
                const currentTxDna = strictNormalize(res.transaction.description);

                const learned = learnedAssociations.find((la: any) => {
                    const learnedDna = la.normalizedDescription;
                    return learnedDna === currentTxDna || getConfidenceScore(learnedDna, currentTxDna) >= 95;
                });

                if (learned) {
                    const church = churches.find((c: any) => c.id === learned.churchId);
                    if (church) {
                        identifiedCount++;

                        // Atualiza no banco
                        if (!res.transaction.id.includes('ghost') && !res.transaction.id.includes('sim')) {
                            await consolidationService.updateTransactionStatus(res.transaction.id, 'identified');
                        }

                        nextResults.push({
                            ...res,
                            status: ReconciliationStatus.IDENTIFIED,
                            church: church,
                            matchMethod: MatchMethod.LEARNED,
                            similarity: 100,
                            contributor: { 
                                name: learned.contributorNormalizedName, 
                                amount: res.transaction.amount,
                                cleanedName: learned.contributorNormalizedName 
                            },
                            contributorAmount: res.transaction.amount,
                            suggestion: undefined
                        });
                        continue;
                    }
                }
            }
            nextResults.push(res);
        }

        if (identifiedCount > 0) {
            setMatchResults(nextResults);

            const incomeResults = nextResults.filter((r: MatchResult) => {
                const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
                return val >= 0;
            });
            const expenseResults = nextResults.filter((r: MatchResult) => {
                const val = r.status === ReconciliationStatus.PENDING ? (r.contributorAmount || 0) : r.transaction.amount;
                return val < 0;
            });

            setReportPreviewData({
                income: groupResultsByChurch(incomeResults),
                expenses: { 'all_expenses_group': expenseResults }
            });

            showToast(`Sucesso: ${identifiedCount} itens identificados pela IA!`, "success");
            if (onAfterIdentification) onAfterIdentification(nextResults);
        } else {
            showToast("IA: Nenhuma linha coincide com o aprendizado salvo.", "error");
        }

        setIsLoading(false);
    }, [reconciliation, referenceData, setIsLoading, showToast, onAfterIdentification]);

    return { runAiAutoIdentification };
};

