import { Transaction } from '../types';
import { Logger } from './monitoringService';
import { DateResolver } from '../core/processors/DateResolver';
import { NameResolver } from '../core/processors/NameResolver';

// Cache global para evitar race conditions em uploads simultâneos
const hashesInFlight = new Set<string>();

export const LaunchService = {
    /**
     * Gera o DNA base da transação focado no conteúdo BRUTO para estabilidade.
     */
    computeBaseHash: (t: any, userId: string, bankId: string) => {
        let rawDate = String(t.date || t.transaction_date || '').trim();
        let isoDate = rawDate;
        if (rawDate && !/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
            const resolved = DateResolver.resolveToISO(rawDate, new Date().getFullYear());
            if (resolved) isoDate = resolved;
        }
        const finalDate = isoDate || rawDate || 'SEM_DATA';

        // IMPORTANTE: Usa rawDescription (original do banco) para o hash, 
        // evitando que edições no frontend mudem o DNA da transação.
        const descSource = (t.rawDescription || t.description || 'SEM_DESC').trim().toUpperCase();
        const amountVal = Number(t.amount || 0).toFixed(2);
        const methodVal = String(t.paymentMethod || t.pix_key || 'OUTROS').trim().toUpperCase();

        const raw = `U${userId}|B${bankId}|D${finalDate}|V${amountVal}|M${methodVal}|T${descSource}`;

        let hash = 0;
        for (let i = 0; i < raw.length; i++) {
            const char = raw.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash; 
        }
        return `b${Math.abs(hash).toString(36)}`;
    },

    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || !transactions || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions ? transactions.length : 0 };
        }

        const totalReceived = transactions.length;
        const isUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
        const currentBankId = isUuid ? bankId : null;
        const hashBankId = bankId;

        try {
            // 1. Busca hashes reais já persistidos
            const existingData = await consolidationService.getExistingTransactionsForDedup(userId);
            const existingHashes = new Set(existingData.map(t => t.row_hash).filter(Boolean));

            // 2. Analisamos índices de ocorrência
            const dbOccurrenceMax = new Map<string, number>();
            existingHashes.forEach((h: any) => {
                const parts = h.split('_');
                if (parts.length === 2) {
                    const base = parts[0];
                    const count = parseInt(parts[1]);
                    if (!isNaN(count)) {
                        const currentMax = dbOccurrenceMax.get(base) ?? -1;
                        if (count > currentMax) dbOccurrenceMax.set(base, count);
                    }
                }
            });

            const batchOccurrenceMap = new Map<string, number>();

            const toPersist = transactions
                .map(item => {
                    let isoDate = item.date;
                    if (isoDate && !/^\d{4}-\d{2}-\d{2}$/.test(isoDate)) {
                        const resolved = DateResolver.resolveToISO(isoDate, new Date().getFullYear());
                        if (resolved) isoDate = resolved;
                    }

                    const baseHash = this.computeBaseHash({ ...item, date: isoDate }, userId, hashBankId);

                    const baseDbIndex = (dbOccurrenceMax.get(baseHash) ?? -1) + 1;
                    const batchIndex = batchOccurrenceMap.get(baseHash) || 0;
                    const finalIndex = baseDbIndex + batchIndex;

                    const finalRowHash = `${baseHash}_${finalIndex}`;

                    // DEDUPE TRIPLO: Banco + Em trânsito + Lote Atual
                    if (existingHashes.has(finalRowHash) || hashesInFlight.has(finalRowHash)) {
                        return null; 
                    }

                    batchOccurrenceMap.set(baseHash, batchIndex + 1);
                    hashesInFlight.add(finalRowHash); // Marca como "sendo processado"

                    return {
                        transaction_date: isoDate,
                        amount: item.amount,
                        description: item.description, 
                        type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: currentBankId ? (item.paymentMethod || 'OUTROS') : bankId, 
                        source: source,
                        user_id: userId,
                        bank_id: currentBankId,
                        row_hash: finalRowHash,
                        status: 'pending' as const
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            const novosCount = toPersist.length;

            if (novosCount > 0) {
                await consolidationService.addTransactions(toPersist as any);
            }

            // Limpeza do cache in-flight após gravação (opcional, ou manter por alguns segundos)
            setTimeout(() => {
                toPersist.forEach(t => { if(t.row_hash) hashesInFlight.delete(t.row_hash); });
            }, 5000);

            return { added: novosCount, skipped: totalReceived - novosCount, total: totalReceived };

        } catch (e: any) {
            // Em caso de erro, limpa os hashes do voo para permitir nova tentativa
            hashesInFlight.clear();
            Logger.error(`[Launch:PERSISTENCE_ERROR]`, e);
            throw e;
        }
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<boolean> {
        try {
            return await consolidationService.deletePendingTransactions(userId, bankId);
        } catch (error) {
            throw error;
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';
import { useUI } from '../contexts/UIContext';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds
}: any) => {
    const { showToast } = useUI();
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    // ✅ Normalizadores para dedupe lógico
    const normalizeDate = (d: any) => {
        if (!d) return '';
        const dt = new Date(d);
        if (isNaN(dt.getTime())) return String(d);
        return dt.toISOString().slice(0, 10);
    };

    const normalizeText = (t: any) =>
        String(t || '')
            .toLowerCase()
            .trim()
            .replace(/\s+/g, ' ');

    const normalizeAmount = (v: any) =>
        Number(v || 0).toFixed(2);

    const buildKey = (tx: any, bankId: string) =>
        `${normalizeDate(tx.date)}|${normalizeText(tx.description)}|${normalizeAmount(tx.amount)}|${bankId}`;

    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning || isHydrating.current) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            // Busca as pendências reais do banco (limite de 100k)
            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                if (forceClearUI) {
                    setBankStatementFile(() => []);
                    setSelectedBankIds(() => []);
                }
                isHydrating.current = false;
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                let bankId = t.bank_id;
                if (!bankId && t.pix_key && t.pix_key.includes('-')) {
                    bankId = t.pix_key;
                }
                const finalBankId = bankId || 'virtual';

                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: t.pix_key || 'OUTROS',
                    cleanedDescription: t.description,
                    bank_id: t.bank_id
                };

                if (!groupedByBank[finalBankId]) groupedByBank[finalBankId] = [];
                groupedByBank[finalBankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId.includes('gmail')
                    ? 'Importação Gmail'
                    : (bankId === 'virtual' ? 'Lista Virtual' : `Lista Viva Sincronizada`),
                processedTransactions: txs,
                isRestored: true
            }));

            // ✅ MERGE INTELIGENTE (UNION)
            setBankStatementFile((prev: any[]) => {
                // Se a UI está vazia, simplesmente usa o que veio do banco
                if (!prev || prev.length === 0) return restoredFiles;

                const finalMap = new Map<string, any>();

                // 1. Preserva o que já está na UI (pode ter arquivos em processamento)
                prev.forEach(f => finalMap.set(f.bankId, f));

                // 2. Adiciona/Atualiza com o que veio do Banco
                restoredFiles.forEach(dbFile => {
                    if (finalMap.has(dbFile.bankId)) {
                        const uiFile = finalMap.get(dbFile.bankId);
                        const txMap = new Map<string, Transaction>();

                        // Mapeia transações da UI
                        uiFile.processedTransactions.forEach((tx: Transaction) => {
                            const key = tx.id && !tx.id.includes('sim') ? tx.id : buildKey(tx, dbFile.bankId);
                            txMap.set(key, tx);
                        });

                        // Funde com as do banco (o Banco é a "Verdade de Persistência")
                        dbFile.processedTransactions.forEach((tx: Transaction) => {
                            const key = tx.id; // Transações do banco SEMPRE têm ID real
                            txMap.set(key, tx);
                        });

                        finalMap.set(dbFile.bankId, {
                            ...uiFile,
                            processedTransactions: Array.from(txMap.values())
                        });
                    } else {
                        finalMap.set(dbFile.bankId, dbFile);
                    }
                });

                return Array.from(finalMap.values());
            });

            setSelectedBankIds((prev: string[]) => {
                const availableIds = restoredFiles.map(f => f.bankId);
                return Array.from(new Set([...prev, ...availableIds]));
            });

        } catch (err: any) {
            console.error("[Lista Viva] Erro na hidratação:", err);
        } finally {
            isHydrating.current = false;
        }
    }, [user, setBankStatementFile, setSelectedBankIds, isCleaning]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
            // Após persistir, força uma hidratação para sincronizar os IDs do banco com a UI
            await hydrate(false);
            return stats;
        } catch (e: any) {
            showToast("Erro no Lançamento: " + (e.message || "Erro de rede."), "error");
            throw e; 
        }
    }, [user, showToast, hydrate]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile([]);
                setSelectedBankIds([]);
            }
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';
import { DateResolver } from '../core/processors/DateResolver';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    /**
     * Adiciona transações em lote com CHUNKING para evitar estouro de buffer e timeout.
     */
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const sanitizedPayload = transactions
                .map(t => {
                    const amount = Number(t.amount);
                    let finalDate = t.transaction_date;

                    if (finalDate && !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        const resolved = DateResolver.resolveToISO(finalDate, new Date().getFullYear());
                        if (resolved) finalDate = resolved;
                    }

                    if (!finalDate || !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        finalDate = new Date().toISOString().split('T')[0];
                    }

                    return {
                        transaction_date: finalDate,
                        amount: isNaN(amount) ? 0 : amount,
                        description: t.description,
                        type: t.type || (amount >= 0 ? 'income' : 'expense'),
                        pix_key: t.pix_key || null,
                        source: t.source || 'file',
                        user_id: t.user_id,
                        bank_id: t.bank_id || null, 
                        status: t.status || 'pending',
                        row_hash: t.row_hash
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null && !!item.user_id);

            if (sanitizedPayload.length === 0) return [];

            const CHUNK_SIZE = 100; // Reduzido para maior estabilidade em lotes grandes
            const results = [];

            for (let i = 0; i < sanitizedPayload.length; i += CHUNK_SIZE) {
                const chunk = sanitizedPayload.slice(i, i + CHUNK_SIZE);

                const { data, error } = await supabase
                    .from('consolidated_transactions')
                    .insert(chunk)
                    .select('*'); 

                if (error) {
                    console.error("[Consolidation:INSERT_ERROR]", error);
                    throw new Error(error.message);
                }
                if (data) results.push(...data);
            }

            return results;
        } catch (e: any) {
            console.error("[Consolidation:CRITICAL_FAIL]", e);
            throw e;
        }
    },

    updateTransactionStatus: async (id: string, status: 'pending' | 'identified' | 'resolved') => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .update({ status })
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao atualizar status:", error);
            return false;
        }
    },

    /**
     * Recupera hashes existentes com limite de 100k para evitar falsos positivos em uploads duplicados.
     */
    getExistingTransactionsForDedup: async (userId: string) => {
        try {
            if (!userId) throw new Error("UserID é obrigatório.");

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('row_hash')
                .eq('user_id', userId)
                .limit(100000); // 🚀 ADEUS LIMITE DE 1000

            if (error) throw error;
            return data || [];
        } catch (e: any) {
            throw e;
        }
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!userId) return false;

            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId && bankId !== 'all') {
                const isVirtual = bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank';
                const isProbablyUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
                if (isVirtual || !isProbablyUuid) query = query.is('bank_id', null);
                else query = query.eq('bank_id', bankId);
            }
            const { error } = await query;
            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    },

    /**
     * Recupera transações pendentes sem o teto de 1000 registros do Supabase.
     */
    getPendingTransactions: async (userId: string) => {
        try {
            if (!userId) return [];

            const { data, error } = await supabase
                .from('consolidated_transactions')
                .select('id, transaction_date, amount, description, type, bank_id, row_hash, pix_key')
                .eq('user_id', userId)
                .eq('status', 'pending')
                .order('transaction_date', { ascending: false })
                .limit(100000); // 🚀 ADEUS LIMITE DE 1000

            if (error) throw error;
            return data || [];
        } catch (e: any) {
            throw e; 
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    }
};

